#define IN_RANGE(x, minv, maxv) ((x) >= (minv) && (x) <= (maxv))
#define MIN(a, b) ((a) <= (b) ? (a) : (b))

__kernel void dynproc_kernel(
    int iteration,
    __global int *gpuWall,
    __global int *gpuSrc,
    __global int *gpuResults,
    int cols,
    int rows,
    int startStep,
    int border,
    int HALO,
    __local int *prev,
    __local int *result,
    __global int *outputBuffer)
{
    (void)rows;
    (void)outputBuffer;

    int bx = (int)get_group_id(0);
    int tx = (int)get_local_id(0);
    int BLOCK_SIZE = (int)get_local_size(0);

    int small_block_cols = BLOCK_SIZE - iteration * HALO * 2;

    int blkX = small_block_cols * bx - border;
    int blkXmax = blkX + BLOCK_SIZE - 1;

    int xidx = blkX + tx;

    int validXmin = (blkX < 0) ? (-blkX) : 0;
    int validXmax = (blkXmax > cols - 1) ? (BLOCK_SIZE - 1 - (blkXmax - cols + 1)) : (BLOCK_SIZE - 1);

    int W = tx - 1;
    int E = tx + 1;

    W = (W < validXmin) ? validXmin : W;
    E = (E > validXmax) ? validXmax : E;

    int isValid = IN_RANGE(tx, validXmin, validXmax);

    if (IN_RANGE(xidx, 0, cols - 1)) {
        prev[tx] = gpuSrc[xidx];
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    int computed = 0;
    for (int i = 0; i < iteration; i++) {
        computed = 0;
        if (IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) && isValid) {
            computed = 1;
            int left = prev[W];
            int up = prev[tx];
            int right = prev[E];
            int shortest = MIN(left, up);
            shortest = MIN(shortest, right);
            int index = cols * (startStep + i) + xidx;
            result[tx] = shortest + gpuWall[index];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (i == iteration - 1)
            break;

        if (computed) {
            prev[tx] = result[tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    if (computed) {
        gpuResults[xidx] = result[tx];
    }
}
